/**
 * @brief Merges two pre-sorted arrays of integers into a single sorted array
 * 
 * @param arr1 First sorted array of integers
 * @param size1 Size of the first array
 * @param arr2 Second sorted array of integers
 * @param size2 Size of the second array
 * @return int* Pointer to the newly created merged sorted array
 * 
 * Time Complexity: O(n+m) where n and m are sizes of input arrays
 * Space Complexity: O(n+m) for the result array
 */
int* mergeSortedArrays(const int* arr1, int size1, const int* arr2, int size2) {
    int* result = new int[size1 + size2];
    int i = 0, j = 0, k = 0;

    // Compare elements from both arrays and add the smaller one to result
    while (i < size1 && j < size2) {
        if (arr1[i] <= arr2[j]) {
            result[k++] = arr1[i++];
        } else {
            result[k++] = arr2[j++];
        }
    }

    // Copy remaining elements from arr1 if any
    while (i < size1) {
        result[k++] = arr1[i++];
    }

    // Copy remaining elements from arr2 if any
    while (j < size2) {
        result[k++] = arr2[j++];
    }

    return result;
}
