/// Merges two sorted arrays of integers into a single sorted array.
///
/// # Arguments
///
/// * `array1` - The first sorted array of integers
/// * `array2` - The second sorted array of integers
///
/// # Returns
///
/// A new vector containing all elements from both input arrays in sorted order.
///
/// # Example
///
/// ```
/// let arr1 = vec![1, 3, 5, 7];
/// let arr2 = vec![2, 4, 6, 8];
/// let merged = merge_sorted_arrays(arr1, arr2);
/// assert_eq!(merged, vec![1, 2, 3, 4, 5, 6, 7, 8]);
/// ```
pub fn merge_sorted_arrays(array1: Vec<i32>, array2: Vec<i32>) -> Vec<i32> {
    let mut result = Vec::with_capacity(array1.len() + array2.len());
    let mut i = 0;
    let mut j = 0;

    while i < array1.len() && j < array2.len() {
        if array1[i] <= array2[j] {
            result.push(array1[i]);
            i += 1;
        } else {
            result.push(array2[j]);
            j += 1;
        }
    }

    // Add any remaining elements from array1
    while i < array1.len() {
        result.push(array1[i]);
        i += 1;
    }

    // Add any remaining elements from array2
    while j < array2.len() {
        result.push(array2[j]);
        j += 1;
    }

    result
}
