// AggregateMetrics calculates the average, maximum, and minimum values from a slice of integers.
// It returns three integers representing the average (rounded), maximum, and minimum values.
// If the input slice is empty, it returns 0, 0, 0.
func AggregateMetrics(numbers []int) (avg, max, min int) {
	if len(numbers) == 0 {
		return 0, 0, 0
	}

	sum := 0
	max = numbers[0]
	min = numbers[0]

	for _, num := range numbers {
		sum += num
		if num > max {
			max = num
		}
		if num < min {
			min = num
		}
	}

	avg = sum / len(numbers)
	return avg, max, min
}
