fn calculate_discount(original_price: f64, discount_percentage: f64) -> f64 {
    // Ensure the discount percentage is between 0 and 100
    let clamped_discount = discount_percentage.max(0.0).min(100.0);

    // Calculate the discount amount by multiplying original price with discount percentage divided by 100
    let discount_amount = original_price * (clamped_discount / 100.0);

    // Subtract the discount amount from the original price to get the discounted price
    let discounted_price = original_price - discount_amount;

    // Return the discounted price rounded to 2 decimal places to handle floating-point precision
    (discounted_price * 100.0).round() / 100.0
