/**
 * Calculates the nth Fibonacci number
 * @param n Position in the Fibonacci sequence (0-indexed)
 * @return The nth Fibonacci number
 */
int calculateFibonacci(int n) {
    // Handle base cases: F(0) = 0 and F(1) = 1
    if (n <= 0) return 0;
    if (n == 1) return 1;

    // Initialize first two Fibonacci numbers
    int a = 0;  // F(0)
    int b = 1;  // F(1)
    int result = 0;  // Will hold the final result

    // Calculate Fibonacci numbers iteratively from F(2) to F(n)
    for (int i = 2; i <= n; i++) {
        result = a + b;  // Current Fibonacci number is sum of previous two
        a = b;           // Update a to be the previous Fibonacci number
        b = result;      // Update b to be the current Fibonacci number
    }

    // Return the nth Fibonacci number
    return result;
}
