/*
ProcessCSVData reads and processes data from a CSV file according to specified conditions.

The function takes two parameters:
- filePath: The path to the CSV file to be processed
- processCondition: Determines how the data should be processed. Valid values include:
  * "count": Returns the count of rows in the CSV
  * "sum": Sums numeric values in the first column
  * "filter": Filters rows based on certain criteria
  * "transform": Applies transformation to the data

The function performs validation on the file's existence and readability before
processing any data. If the file cannot be accessed or read, an appropriate
error is returned.
*/
func ProcessCSVData(filePath string, processCondition string) (interface{}, error) {
	// Check if file exists and is readable
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to open CSV file: %w", err)
	}
	defer file.Close()

	// Create CSV reader
	reader := csv.NewReader(file)

	// Read all records from CSV
	records, err := reader.ReadAll()
	if err != nil {
		return nil, fmt.Errorf("failed to read CSV data: %w", err)
	}

	// Process data based on the condition
	switch processCondition {
	case "count":
		return len(records), nil
	case "sum":
		var sum float64
		for i, row := range records {
			if i == 0 { // Skip header row
				continue
			}
			if len(row) > 0 {
				val, err := strconv.ParseFloat(row[0], 64)
				if err != nil {
					return nil, fmt.Errorf("error parsing value in row %d: %w", i, err)
				}
				sum += val
			}
		}
		return sum, nil
	case "filter":
		// Example filter: keep only rows with non-empty first column
		var filteredRecords [][]string
		for _, row := range records {
			if len(row) > 0 && row[0] != "" {
				filteredRecords = append(filteredRecords, row)
			}
		}
		return filteredRecords, nil
	case "transform":
		// Example transformation: convert all strings to uppercase in first column
		transformedRecords := make([][]string, len(records))
		for i, row := range records {
			transformedRow := make([]string, len(row))
			copy(transformedRow, row)
			if len(transformedRow) > 0 {
				transformedRow[0] = strings.ToUpper(transformedRow[0])
			}
			transformedRecords[i] = transformedRow
		}
		return transformedRecords, nil
	default:
		return nil, fmt.Errorf("unknown process condition: %s", processCondition)
	}
}
