 * count of consecutive occurrences. For example, "aabcccccaaa" becomes "a2b1c5a3".
 *
 * If the compressed version would be longer than or equal to the original string,
 * the function returns the original string unchanged.
 *
 * Parameters:
 *   input: The string to compress
 *
 * Returns:
 *   The compressed string if shorter than the original, otherwise the original string
 */
func compressString(input string) string {
	if len(input) <= 1 {
		return input
	}

	var compressed strings.Builder
	currentChar := input[0]
	count := 1

	for i := 1; i < len(input); i++ {
		if input[i] == currentChar {
			count++
		} else {
			compressed.WriteByte(currentChar)
			compressed.WriteString(strconv.Itoa(count))
			currentChar = input[i]
			count = 1
		}
	}

	// Add the last character and its count
	compressed.WriteByte(currentChar)
	compressed.WriteString(strconv.Itoa(count))

	// Return original string if compressed version is not shorter
	if compressed.Len() >= len(input) {
		return input
	}

	return compressed.String()
}
