def consolidate_inventory(current_inventory, new_stock):
    # Function to merge two inventory dictionaries, summing quantities for duplicate items
    # Inputs: current_inventory and new_stock (dictionaries with item names as keys and quantities as values)
    # Returns: consolidated dictionary with combined quantities

    # Handle None inputs
    if current_inventory is None:
        current_inventory = {}
    if new_stock is None:
        new_stock = {}

    # Verify inputs are dictionaries
    if not isinstance(current_inventory, dict) or not isinstance(new_stock, dict):
        raise TypeError("Both inputs must be dictionaries")

    # Create a copy of current inventory to avoid modifying the original
    consolidated = current_inventory.copy()

    # Add items from new stock to consolidated inventory
    for item, quantity in new_stock.items():
        # Validate quantity is a number
        if not isinstance(quantity, (int, float)):
            raise ValueError(f"Quantity for {item} must be a number")

        # Add quantity to existing item or add new item
        if item in consolidated:
            # Validate existing quantity is a number
            if not isinstance(consolidated[item], (int, float)):
                raise ValueError(f"Quantity for {item} in current inventory must be a number")
            consolidated[item] += quantity
        else:
            consolidated[item] = quantity

    return consolidated
