/// Calculates the mean, median, and mode of a list of integers.
///
/// # Arguments
///
/// * `numbers` - A slice of integers to compute statistics on.
///
/// # Returns
///
/// A `Statistics` struct containing the mean, median, and mode of the input.
///
/// # Examples
///
/// ```
/// let numbers = vec![1, 2, 3, 4, 5, 5, 6];
/// let stats = compute_stats(&numbers);
/// assert_eq!(stats.mean, 3.7142857142857144);
/// assert_eq!(stats.median, 4.0);
/// assert_eq!(stats.mode, vec![5]);
///
/// let empty: Vec<i32> = vec![];
/// let empty_stats = compute_stats(&empty);
/// assert!(empty_stats.mean.is_nan());
/// assert!(empty_stats.median.is_nan());
/// assert_eq!(empty_stats.mode, vec![]);
/// ```
#[derive(Debug, PartialEq)]
pub struct Statistics {
    /// The arithmetic mean (average) of the input values
    pub mean: f64,
    /// The median value of the input values
    pub median: f64,
    /// The mode(s) of the input values (most frequently occurring)
    pub mode: Vec<i32>,
}

pub fn compute_stats(numbers: &[i32]) -> Statistics {
    if numbers.is_empty() {
        return Statistics {
            mean: f64::NAN,
            median: f64::NAN,
            mode: vec![],
        };
    }

    // Calculate mean
    let sum: i64 = numbers.iter().map(|&x| x as i64).sum();
    let mean = sum as f64 / numbers.len() as f64;

    // Calculate median
    let mut sorted = numbers.to_vec();
    sorted.sort();
    let median = if numbers.len() % 2 == 0 {
        let mid_right = numbers.len() / 2;
        let mid_left = mid_right - 1;
        (sorted[mid_left] as f64 + sorted[mid_right] as f64) / 2.0
    } else {
        sorted[numbers.len() / 2] as f64
    };

    // Calculate mode
    let mut frequency_map = std::collections::HashMap::new();
    for &num in numbers {
        *frequency_map.entry(num).or_insert(0) += 1;
    }

    let max_frequency = frequency_map.values().max().unwrap_or(&0);
    let mut mode: Vec<i32> = frequency_map
        .iter()
        .filter(|&(_, &count)| count == *max_frequency)
        .map(|(&value, _)| value)
        .collect();
    mode.sort();

    Statistics { mean, median, mode }
}
