// SumSlice calculates the sum of all integers in the provided slice.
// It handles potential integer overflow by checking for overflow conditions.
//
// Parameters:
//   - numbers: A slice of integers to be summed
//
// Returns:
//   - int64: The sum of all integers in the slice
//   - error: An error if integer overflow occurs, nil otherwise
//
// Example:
//   sum, err := SumSlice([]int{math.MaxInt64, 1})
//   if err != nil {
//     fmt.Println("Overflow occurred:", err)
//   } else {
//     fmt.Println("Sum:", sum)
//   }
func SumSlice(numbers []int) (int64, error) {
	var sum int64

	for _, num := range numbers {
		// Convert each int to int64 to ensure consistent types
		num64 := int64(num)

		// Check for potential overflow before adding
		if num64 > 0 && sum > math.MaxInt64-num64 {
			return sum, errors.New("integer overflow: sum exceeds maximum value")
		} else if num64 < 0 && sum < math.MinInt64-num64 {
			return sum, errors.New("integer overflow: sum exceeds minimum value")
		}

		sum += num64
	}

	return sum, nil
}
