// MaxSubarraySum computes the maximum sum of any contiguous subarray within the given array
// using Kadane's Algorithm. If the array is empty, it returns 0. If the array contains only
// negative numbers, it returns the largest negative number in the array.
// Parameters:
//   - nums: An array of integers
// Returns:
//   - The maximum sum of any contiguous subarray, 0 for empty arrays, or the largest
//     negative number if all elements are negative
func MaxSubarraySum(nums []int) int {
	if len(nums) == 0 {
		return 0
	}

	maxSoFar := nums[0]
	maxEndingHere := nums[0]
	allNegative := true
	maxNegative := nums[0]

	for i := 1; i < len(nums); i++ {
		if nums[i] >= 0 {
			allNegative = false
		}
		if nums[i] > maxNegative && nums[i] < 0 {
			maxNegative = nums[i]
		}

		maxEndingHere = max(nums[i], maxEndingHere+nums[i])
		maxSoFar = max(maxSoFar, maxEndingHere)
	}

	if allNegative {
		return maxNegative
	}

	return maxSoFar
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}
