/**
 * Evaluates a mathematical expression in Reverse Polish Notation (RPN).
 * RPN is a notation where operators follow their operands.
 * 
 * @param expression The RPN expression to evaluate (operands and operators separated by spaces)
 * @return The result of evaluating the expression
 * @throws IllegalArgumentException If the expression is malformed (insufficient operands or extra operators)
 * @throws ArithmeticException If division by zero is attempted
 */
public static double evaluateRPNExpression(String expression) {
    if (expression == null || expression.trim().isEmpty()) {
        throw new IllegalArgumentException("Expression cannot be null or empty");
    }

    String[] tokens = expression.trim().split("\\s+");
    Stack<Double> stack = new Stack<>();

    for (String token : tokens) {
        // Process each token in the expression
        if (isOperator(token)) {
            // Handle operators
            if (stack.size() < 2) {
                throw new IllegalArgumentException("Insufficient operands for operator: " + token);
            }

            double operand2 = stack.pop(); // Second operand (popped first)
            double operand1 = stack.pop(); // First operand (popped second)

            // Perform the operation
            switch (token) {
                case "+":
                    stack.push(operand1 + operand2);
                    break;
                case "-":
                    stack.push(operand1 - operand2);
                    break;
                case "*":
                    stack.push(operand1 * operand2);
                    break;
                case "/":
                    // Check for division by zero
                    if (operand2 == 0) {
                        throw new ArithmeticException("Division by zero");
                    }
                    stack.push(operand1 / operand2);
                    break;
                default:
                    throw new IllegalArgumentException("Unsupported operator: " + token);
            }
        } else {
            // Handle operands
            try {
                stack.push(Double.parseDouble(token));
            } catch (NumberFormatException e) {
                throw new IllegalArgumentException("Invalid token: " + token);
            }
        }
    }

    // After processing all tokens, we should have exactly one value on the stack
    if (stack.size() != 1) {
        throw new IllegalArgumentException("Malformed expression: extra operands");
    }

    return stack.pop();
}

// Helper method to check if a token is an operator
private static boolean isOperator(String token) {
    return token.equals("+") || token.equals("-") || token.equals("*") || token.equals("/");
}
